mapper.select:
SELECT 
FROM simulation_scenario
WHERE id = #{id}
  AND owner_id = #{ownerId}
  AND archived = 0
LIMIT 1

SELECT 
FROM simulation_scenario
WHERE owner_id = #{ownerId}
  AND archived = 0
ORDER BY created_at DESC, id DESC
LIMIT #{limit} OFFSET #{offset}

mapper.update:
UPDATE simulation_scenario
SET name = #{name},
    description = #{description},
    objective = #{objective},
    config_json = CAST(#{configJson} AS JSON),
    version = version + 1
WHERE id = #{id}
  AND owner_id = #{ownerId}
  AND version = #{version}
  AND archived = 0

mapper.select:
SELECT COUNT(*)
FROM experiment_task
WHERE scenario_id = #{scenarioId}

mapper.update:
UPDATE simulation_scenario
SET archived = 1,
    version = version + 1
WHERE id = #{id}
  AND owner_id = #{ownerId}
  AND archived = 0
